module top_module(
  input in,
  output reg out  // Changed from wire to reg
);reg obf_prev_state;

  always @(in) begin
    if (in === 1'b0 || in === 1'b1) begin
      obf_prev_state <= in;
      out <= in;
    end
  end

  always @(*) begin
    if (in === 1'bx) begin
      out <= obf_prev_state;
    end
  end

endmodule
